// ── Particle canvas ──
function Particles() {
  const ref = useRef(null)
  useEffect(() => {
    const cvs = ref.current, ctx = cvs.getContext('2d')
    let W, H, parts = [], raf
    const resize = () => { W = cvs.width = innerWidth; H = cvs.height = innerHeight }
    resize(); window.addEventListener('resize', resize)
    for (let i = 0; i < 90; i++) parts.push({
      x: Math.random()*1200, y: Math.random()*700,
      r: 0.6 + Math.random()*2.2, vx: (Math.random()-.5)*.28, vy: -.08 - Math.random()*.38,
      a: .06 + Math.random()*.38, col: Math.random()>.5 ? '184,149,42' : '60,180,106'
    })
    const tick = () => {
      ctx.clearRect(0,0,W,H)
      parts.forEach(p => {
        p.x += p.vx; p.y += p.vy
        if (p.y < -8) { p.y = H+8; p.x = Math.random()*W }
        if (p.x < -8) p.x = W+8; if (p.x > W+8) p.x = -8
        ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2)
        ctx.fillStyle = `rgba(${p.col},${p.a})`; ctx.fill()
      })
      raf = requestAnimationFrame(tick)
    }
    tick()
    return () => { cancelAnimationFrame(raf); window.removeEventListener('resize', resize) }
  }, [])
  return <canvas ref={ref} style={{position:'fixed',inset:0,pointerEvents:'none',zIndex:0}}/>
}

