// ── DonutChart ──
function DonutChart({lang}) {
  const circ = 2*Math.PI*80
  const entries = [
    {pct:40,col:"#B8952A",val:"$120K"},{pct:10,col:"#3CB46A",val:"$30K"},
    {pct:7,col:"#E8C547",val:"$20K"},{pct:13,col:"#5B8AF5",val:"$40K"},
    {pct:17,col:"#F08040",val:"$50K"},{pct:13,col:"#C070E0",val:"$40K"},
  ]
  const labels = lang==="en"
    ? ["Tech dev (CTO + contracts)","Sharia certification","Legal registration","Security audit","Marketing","Operations (12 months)"]
    : ["Техразработка (CTO + контракты)","Шариатская сертификация","Юридическая регистрация","Аудит безопасности","Маркетинг","Операции (12 мес.)"]
  const total = entries.reduce((s,e)=>s+e.pct,0)
  let offset = 0
  const segs = entries.map(e=>{const arc=(e.pct/total)*circ;const s={...e,arc,offset};offset+=arc;return s})
  return (
    <div style={{display:'flex',gap:32,alignItems:'center',flexWrap:'wrap',justifyContent:'center'}}>
      <div style={{position:'relative',flexShrink:0}}>
        <svg width="206" height="206" viewBox="0 0 206 206">
          <circle cx="103" cy="103" r="80" fill="none" stroke="rgba(255,255,255,.04)" strokeWidth="30"/>
          {segs.map((s,i)=>(
            <motion.circle key={i} cx="103" cy="103" r="80" fill="none"
              stroke={s.col} strokeWidth="30"
              strokeDashoffset={-s.offset}
              transform="rotate(-90 103 103)"
              initial={{strokeDasharray:`0 ${circ}`}}
              animate={{strokeDasharray:`${s.arc} ${circ-s.arc}`}}
              transition={{duration:1.1,delay:i*.12,ease:[0.22,1,0.36,1]}}/>
          ))}
        </svg>
        <div style={{position:'absolute',inset:0,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center'}}>
          <div style={{fontSize:'1.5rem',fontWeight:900,color:'var(--gold)'}}>$300K</div>
          <div style={{fontSize:'.72rem',color:'var(--dim)'}}>{lang==="en"?"Seed Target":"Цель раунда"}</div>
        </div>
      </div>
      <div style={{display:'flex',flexDirection:'column',gap:9}}>
        {segs.map((s,i)=>(
          <motion.div key={i} style={{display:'flex',alignItems:'center',gap:10}}
            initial={{opacity:0,x:20}} animate={{opacity:1,x:0}} transition={{delay:.3+i*.09,...spring}}>
            <div style={{width:11,height:11,borderRadius:3,background:s.col,flexShrink:0}}/>
            <div style={{fontSize:'.8rem',color:'var(--dim)',flex:1}}>{labels[i]}</div>
            <div style={{fontWeight:700,fontSize:'.86rem'}}>{s.val}</div>
          </motion.div>
        ))}
      </div>
    </div>
  )
}

