// ══════════ ROOT ══════════
const SLIDES = [S0,S1,S2,S3,S4,S5,S6,S7,S8,S9,S10,S11,S12,S13]
const TOTAL = SLIDES.length

export default function App() {
  const [cur,setCur] = useState(0)
  const [lang,setLang] = useState('en')
  const t = T[lang]
  const go = useCallback((dir)=>{setCur(c=>Math.max(0,Math.min(TOTAL-1,c+dir)))},[])
  useEffect(()=>{const h=e=>{if(e.key==='ArrowRight'||e.key==='ArrowDown'||e.key===' ')go(1);if(e.key==='ArrowLeft'||e.key==='ArrowUp')go(-1)};window.addEventListener('keydown',h);return()=>window.removeEventListener('keydown',h)},[go])
  useEffect(()=>{let cd=false;const h=e=>{if(cd)return;cd=true;go(e.deltaY>0?1:-1);setTimeout(()=>cd=false,880)};window.addEventListener('wheel',h,{passive:true});return()=>window.removeEventListener('wheel',h)},[go])
  useEffect(()=>{let tx=0,ty=0;const ts=e=>{tx=e.touches[0].clientX;ty=e.touches[0].clientY};const te=e=>{const dx=e.changedTouches[0].clientX-tx;const dy=e.changedTouches[0].clientY-ty;Math.abs(dx)>Math.abs(dy)?go(dx<0?1:-1):go(dy<0?1:-1)};window.addEventListener('touchstart',ts,{passive:true});window.addEventListener('touchend',te);return()=>{window.removeEventListener('touchstart',ts);window.removeEventListener('touchend',te)}},[go])
  const Slide = SLIDES[cur]
  return (
    <>
      <Background3D scene={cur}/>
      <AtmosphereParticles scene={cur}/>
      <div style={{position:'fixed',top:0,left:0,right:0,zIndex:100,display:'flex',alignItems:'center',justifyContent:'space-between',padding:'10px 24px',background:'linear-gradient(to bottom,rgba(6,10,8,.96),transparent)'}}>
        <img src={LOGO} alt="AM Network" style={{height:31}}/>
        <div style={{display:'flex',gap:6}}>
          {SLIDES.map((_,i)=>(
            <button key={i} onClick={()=>setCur(i)} style={{width:8,height:8,borderRadius:'50%',background:i===cur?'var(--gold)':'rgba(255,255,255,.18)',transform:i===cur?'scale(1.45)':'scale(1)',transition:'all .28s',padding:0,border:'none',cursor:'pointer'}}/>
          ))}
        </div>
        <button onClick={()=>setLang(l=>l==='en'?'ru':'en')} style={{background:'rgba(255,255,255,.07)',border:'1px solid rgba(255,255,255,.14)',color:'var(--text)',padding:'5px 15px',borderRadius:20,fontSize:13,fontWeight:600,cursor:'pointer'}}>
          {t.langBtn}
        </button>
      </div>
      <div style={{position:'fixed',inset:0,overflow:'hidden',zIndex:10}}>
        <AnimatePresence mode="wait">
          <Slide key={cur+'-'+lang} t={t} lang={lang}/>
        </AnimatePresence>
      </div>
      {cur>0&&<motion.button onClick={()=>go(-1)} initial={{opacity:0}} animate={{opacity:1}} style={{position:'fixed',left:13,top:'50%',transform:'translateY(-50%)',zIndex:90,background:'rgba(255,255,255,.06)',border:'1px solid rgba(255,255,255,.12)',borderRadius:'50%',width:42,height:42,fontSize:'1.1rem',color:'var(--text)',cursor:'pointer'}} whileHover={{background:'rgba(184,149,42,.2)',borderColor:'var(--gold)'}}>←</motion.button>}
      {cur<TOTAL-1&&<motion.button onClick={()=>go(1)} initial={{opacity:0}} animate={{opacity:1}} style={{position:'fixed',right:13,top:'50%',transform:'translateY(-50%)',zIndex:90,background:'rgba(255,255,255,.06)',border:'1px solid rgba(255,255,255,.12)',borderRadius:'50%',width:42,height:42,fontSize:'1.1rem',color:'var(--text)',cursor:'pointer'}} whileHover={{background:'rgba(184,149,42,.2)',borderColor:'var(--gold)'}}>→</motion.button>}
      <div style={{position:'fixed',bottom:17,right:21,fontSize:'.73rem',color:'var(--dim)',zIndex:90,fontWeight:600,letterSpacing:1}}>{cur+1} / {TOTAL}</div>
    </>
  )
}
